function LMainCityEnterBubble:IsBubbleTranValid()
    return self._bubbleTran and CS.IsValidObject(self._bubbleTran)
end

function LMainCityEnterBubble:InitBubbleRoot()
    local fightCanvas = LGameUI.GetUIFight()

    --在包一层  "UIBubbleStick"
    local rootCanvas = CS.FindTrans(fightCanvas, "UIBubbleStick")
    if not rootCanvas then
        self._parentTrans = CS.NewObject("UIBubbleStick", fightCanvas)
    end

    self._uiCamera = LGameUI.GetUICamera()
    self._sceneCamera = gLGameScene:GetCurrentSceneCamera()

    local parentTrans = CS.FindTrans(rootCanvas, LMainCityEnterBubble.ROOT)
    if not parentTrans then
        parentTrans = CS.NewObject(LMainCityEnterBubble.ROOT, rootCanvas)
    end
    self._parentTrans = parentTrans
end

function LMainCityEnterBubble:OnLoaded(dp)
    local instanceTrans = dp:GetDisplayTrans()
    local parentTrans = self._parentTrans
    if instanceTrans then
        local instanceGo = instanceTrans.gameObject
        self._bubbleTran = instanceTrans

        local follow = self._bubbleTran:GetComponent(typeofBtHudFollow)
        if not follow then
            follow = self._bubbleTran.gameObject:AddComponent(typeofBtHudFollow)
        end
        self._bubbleFollow = follow
        
        local textBgTrans = CS.FindTrans(self._bubbleTran, "timeBg")
        self._textBgTrans = textBgTrans
        self._bg = CS.FindTrans(textBgTrans, "bg")
        self._text = CS.FindTrans(textBgTrans, "text")
        self._redPoint = CS.FindTrans(textBgTrans, "redPoint")

        self._lock_bg = CS.FindTrans(textBgTrans, "lock_bg")
        self._lock = CS.FindTrans(textBgTrans, "lock")
        self._lock_Text = CS.FindTrans(textBgTrans, "lock_Text")

        local titleBgTrans = CS.FindTrans(self._bubbleTran, "titleBg")
        self._title = CS.FindTrans(titleBgTrans, "text")
     
        self._titleBgTrans = titleBgTrans
  
        self:OnUpdateTrans()
        
        --添加下scale 
        local btnScale = self._bubbleTran:GetComponent(typeofBtHudScale)
        if not btnScale then
            btnScale = self._bubbleTran.gameObject:AddComponent(typeofBtHudScale)
        end
        self._bubbleScale = btnScale

        self:SetScaleTrans()

        self:UpdateLockState()
    end
end

-----------------------------------------
function LMainCityEnterBubble:ClearDpPrefab()
    if self._dpPrefab then
        self._dpPrefab:Destroy()
        self._dpPrefab = nil
    end
end

function LMainCityEnterBubble:CreateBubble(prefabName, tranRootName, lockFunctionId)
    LMainCityEnterBubble.ROOT = tranRootName == nil and "UIBubbleStick" or tranRootName
    self._lockFunctionId = lockFunctionId
    self:InitBubbleRoot()
    if self:IsBubbleTranValid() then
        if not string.isempty(prefabName) and prefabName ~= self._name then
            self:ClearDpPrefab()
        else
            return
        end
    end

    if not string.isempty(prefabName) then
        self._name = prefabName
    end

    self:ClearDpPrefab()

    local dpPrefab = LDisplayPrefab:New()
    self._dpPrefab = dpPrefab
    dpPrefab:CreatePrefab(self._parentTrans, self._path, self._name)
    dpPrefab:SetLoadedFunction(function (dp)
        self:OnLoaded(dp)
    end)
    dpPrefab:StartLoad()
end

function LMainCityEnterBubble:DestroyBubble()
    if self._isDetroyed then return end

    if self._timer then
        LxTimer.LoopTimeStop(self._timer)
        self._timer = nil
    end
    self:ClearDpPrefab()
    LxNodeBase.Dispose(self)
    self._isDetroyed = true
end

function LMainCityEnterBubble:SetBuildingTrans(buildingTrans, offset)
    self._buildingTrans = buildingTrans

    local followTrans = CS.FindTrans(self._buildingTrans, "FollowTrans")
    if not followTrans then
        followTrans = CS.FindTrans(self._buildingTrans, "building/FollowTrans")
    end 
    self._followTrans = followTrans or self._buildingTrans

    self._offset = offset
    self:OnUpdateTrans()
    
    self._scaleTrans = CS.FindTrans(self._buildingTrans, "building")
    self:SetScaleTrans()
end

function LMainCityEnterBubble:OnUpdateTrans()
    if not self:IsBubbleTranValid() then return end

    self._bubbleFollow:Init(self._uiCamera, self._sceneCamera)

    if not self._buildingTrans then
        if LOG_INFO_ENABLED then
            printInfoNR2("cjh------------_buildingTrans--", "等待节点重新创建")
        end
        return
    end
    
    self._bubbleFollow:DoFollowTrans(self._followTrans, self._offset)

    --更新文本之类的操作
    local strId = self._bubbleText[self._buildingTrans.name]
    local str = strId == nil and "noname" or ccClientText(strId)
    self:SetXTextContent(self._lock_Text, str)
    self:SetXTextContent(self._text, str)
end

function LMainCityEnterBubble:SetScaleTrans()
    if not self:IsBubbleTranValid() then return end

    if not self._buildingTrans then
        if LOG_INFO_ENABLED then
            printInfoNR2("cjh------------_buildingTrans--", "等待节点重新创建")
        end
        return
    end
    if self._scaleTrans then
        self._bubbleScale:InitSceleTrans(self._scaleTrans)
    end
end


function LMainCityEnterBubble:GetCurRedPoint()
    return self._redPoint
end

function LMainCityEnterBubble:UpdateLockState()
    if not self:IsBubbleTranValid() then return end

    local openid = self._lockFunctionId
    local isOpen = true
    if openid and openid > 0 then
        isOpen = gModelFunctionOpen:CheckIsOpened(openid)
    end
    self:SetGray(not isOpen)
end

function LMainCityEnterBubble:SetGray(isGray)
    if self._isGray == isGray then return end

    self._isGray = isGray
    CS.ShowObject(self._lock,isGray)
    CS.ShowObject(self._lock_Text,isGray)
    CS.ShowObject(self._lock_bg,isGray)
    CS.ShowObject(self._text,not isGray)
    CS.ShowObject(self._bg,not isGray)
end

return LMainCityEnterBubble